sql:
SELECT SUM(oil_produced) AS total_oil_produced
FROM production_data
WHERE well_id = 1;

SELECT total_oil_produced
FROM production_history
WHERE well_id = 1;

SELECT well_name
FROM wells
ORDER BY well_name;

SELECT COUNT(*) AS active_operator_count
FROM operators
WHERE status = 'active';

external_knowledge:
